203	function DetailBody({
204	  data,
205	  onApply,
206	}: {
207	  data: DetailResponse;
208	  onApply: () => void;
209	}) {
210	  const { listing, conditions, sample_videos, eligibility } = data;
211	
212	  const preConditions = useMemo(
213	    () => conditions.filter((c) => c.kind === 'pre'),
214	    [conditions],
215	  );
216	  const postConditions = useMemo(
217	    () => conditions.filter((c) => c.kind === 'post'),
218	    [conditions],
219	  );
220	
221	  const failureByKey = useMemo(() => {
222	    const map = new Map<string, FailedCondition>();
223	    for (const f of eligibility.failed_conditions) {
224	      map.set(conditionKey(f.metric, f.platform), f);
225	    }
226	    return map;
227	  }, [eligibility.failed_conditions]);
228	
229	  const inactiveBanner = getInactiveBanner(listing.status);
230	  const priceLabel = formatPrice(listing.price_cents, listing.currency);
231	
232	  return (
233	    <>
234	      <ScrollView
235	        contentContainerStyle={styles.scrollContent}
236	        showsVerticalScrollIndicator={false}
237	      >
238	        {inactiveBanner ? (
239	          <View style={styles.inactiveBanner} testID="listing-inactive-banner">
240	            <Text style={[textStyles.caption, { color: colors.ink }]}>
241	              {inactiveBanner}
242	            </Text>
243	          </View>
244	        ) : null}
245	
246	        <View style={styles.heroCard} testID="listing-hero">
247	          <Text style={[textStyles.display, { color: colors.ink }]}>
248	            {listing.title}
249	          </Text>
250	          <Text style={[textStyles.h1, styles.priceRow]} testID="listing-price">
251	            {priceLabel}
252	          </Text>
253	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>
254	            Payout after approval
255	          </Text>
256	        </View>
257	
258	        {sample_videos.length > 0 ? (
259	          <Section title="Sample videos">
260	            <View style={styles.sampleList}>
261	              {sample_videos.map((v) => (
262	                <SampleVideoCell key={v.id} video={v} />
263	              ))}
264	            </View>
265	          </Section>
266	        ) : null}
267	
268	        {preConditions.length > 0 ? (
269	          <Section title="Eligibility">
270	            <View style={styles.eligibilityList}>
271	              {preConditions.map((c) => (
272	                <EligibilityRow
273	                  key={c.id}
274	                  condition={c}
275	                  failure={failureByKey.get(conditionKey(c.metric, c.platform)) ?? null}
276	                />
277	              ))}
278	            </View>
279	          </Section>
280	        ) : null}
281	
282	        {postConditions.length > 0 ? (
283	          <Section title="What to film">
284	            <View style={styles.bulletList}>
285	              {postConditions.map((c) => (
286	                <PostConditionRow key={c.id} condition={c} />
287	              ))}
288	            </View>
289	          </Section>
290	        ) : null}
291	
292	        {listing.description ? (
293	          <Section title="Brief">
294	            <Text style={[textStyles.body, { color: colors.ink }]}>
295	              {listing.description}
296	            </Text>
297	          </Section>
298	        ) : null}
299	      </ScrollView>
300	
301	      <FooterCta
302	        listing={listing}
303	        eligibility={eligibility}
304	        onApply={onApply}
305	      />
306	    </>
307	  );
308	}
309	
310	function FooterCta({
311	  listing,
312	  eligibility,
313	  onApply,
314	}: {
315	  listing: ListingRow;
316	  eligibility: DetailResponse['eligibility'];
317	  onApply: () => void;
318	}) {
319	  if (listing.status !== 'active') {
320	    // Inactive listing surfaces its state via the top banner; the CTA is
321	    // hidden outright — a disabled CTA would imply "apply later" which is
322	    // wrong for paused/closed.
323	    return null;
324	  }
325	  if (eligibility.has_active_application) {
326	    return (
327	      <View style={styles.footer}>
328	        <View style={styles.footerInner}>
329	          <StatusPill status="pending" label="Applied" testID="listing-applied-pill" />
330	          <View style={styles.footerCtaWrap}>
331	            <ButtonPrimary
332	              label="Applied"
333	              onPress={onApply}
334	              disabled
335	              testID="listing-cta"
336	            />
337	          </View>
338	        </View>
339	      </View>
340	    );
341	  }
342	  if (!eligibility.eligible) {
343	    return (
344	      <View style={styles.footer}>
345	        <View style={styles.failureSummary} testID="listing-failure-summary">
346	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>
347	            You don&apos;t meet these yet:
348	          </Text>
349	          {eligibility.failed_conditions.map((f) => (
350	            <View key={conditionKey(f.metric, f.platform)} style={styles.bulletRow}>
351	              <View style={styles.bullet} />
352	              <Text style={[textStyles.caption, styles.bulletText]}>
353	                {failureBulletLabel(f)}
354	              </Text>
355	            </View>
356	          ))}
357	        </View>
358	        <View style={styles.footerCtaWrap}>
359	          <ButtonPrimary
360	            label="Not eligible yet"
361	            onPress={onApply}
362	            disabled
363	            testID="listing-cta"
364	          />
365	        </View>
366	      </View>
367	    );
368	  }
369	  return (
370	    <View style={styles.footer}>
371	      <View style={styles.footerCtaWrap}>
372	        <ButtonPrimary
373	          label="Apply to collab"
374	          onPress={onApply}
375	          testID="listing-cta"
376	        />
377	      </View>
378	    </View>
379	  );
380	}
381	
382	function Section({ title, children }: { title: string; children: React.ReactNode }) {
383	  return (
384	    <View style={styles.section}>
385	      <Text style={[textStyles.h2, { color: colors.ink }]}>{title}</Text>
386	      {children}
387	    </View>
388	  );
389	}
