391	function SampleVideoCell({ video }: { video: SampleVideoRow }) {
392	  const label = platformLabel(video.platform);
393	  const onPress = useCallback(() => {
394	    void Linking.openURL(video.url).catch(() => {
395	      // Swallowed intentionally — the link may not resolve in the
396	      // simulator (no TikTok/Instagram app installed). There is no
397	      // actionable retry; the URL is the primary info for the creator.
398	    });
399	  }, [video.url]);
400	  return (
401	    <Pressable
402	      onPress={onPress}
403	      style={[styles.sampleRow, shadows.hard]}
404	      accessibilityRole="link"
405	      accessibilityLabel={`Open ${label} sample${video.caption ? `: ${video.caption}` : ''}`}
406	      testID={`listing-sample-${video.sort_order}`}
407	    >
408	      <View style={styles.sampleText}>
409	        <Text style={[textStyles.body, { color: colors.ink }]}>
410	          {video.caption ?? `${label} sample`}
411	        </Text>
412	        <Text style={[textStyles.caption, { color: colors.ink70 }]} numberOfLines={1}>
413	          {video.url}
414	        </Text>
415	      </View>
416	      <ExternalLink color={colors.ink} size={20} strokeWidth={2.5} />
417	    </Pressable>
418	  );
419	}
