457	function PostConditionRow({ condition }: { condition: ConditionRow }) {
458	  return (
459	    <View style={styles.bulletRow}>
460	      <View style={styles.bullet} />
461	      <Text style={[textStyles.body, styles.bulletText]}>
462	        {postConditionLabel(condition)}
463	      </Text>
464	    </View>
465	  );
