472	function getInactiveBanner(status: ListingStatus): string | null {
473	  switch (status) {
474	    case 'paused':
475	      return 'This campaign is paused. The lister is reviewing pending applications.';
476	    case 'closed':
477	      return 'This campaign is closed and no longer accepting applications.';
478	    default:
479	      return null;
480	  }
481	}
482	
483	function eligibilityRowLabel(c: ConditionRow): string {
484	  const platform = c.platform ? platformLabel(c.platform) : '';
485	  const base = metricLabel(c.metric);
486	  return platform ? `${platform} · ${base}` : base;
487	}
488	
489	function metricLabel(metric: string): string {
490	  switch (metric) {
491	    case 'min_followers':
492	      return 'Minimum followers';
493	    case 'min_avg_views_last_n':
494	      return 'Avg views (last 10)';
495	    case 'min_total_likes':
496	      return 'Total likes';
497	    case 'min_videos_posted':
498	      return 'Videos posted';
499	    case 'verified_only':
500	      return 'Verified account';
501	    default:
502	      return metric;
503	  }
504	}
505	
506	function requiredLabel(c: ConditionRow): string {
507	  if (c.operator === 'bool') {
508	    return `Requires ${c.bool_threshold ? 'yes' : 'no'}`;
509	  }
510	  const threshold = c.numeric_threshold;
511	  if (threshold !== null && threshold !== undefined) {
512	    return `Requires ${formatCount(Number(threshold))}+`;
513	  }
514	  return '—';
515	}
516	
517	function failureDetailLabel(
518	  c: ConditionRow,
519	  f: FailedCondition,
520	): string {
521	  const required = requiredLabel(c);
522	  if (typeof f.actual === 'number') {
523	    return `${required} — you have ${formatCount(f.actual)}`;
524	  }
525	  if (typeof f.actual === 'boolean') {
526	    return `${required} — you are ${f.actual ? 'verified' : 'not verified'}`;
527	  }
528	  return `${required} — no data yet`;
529	}
530	
531	function failureBulletLabel(f: FailedCondition): string {
532	  const platform = f.platform ? platformLabel(f.platform) : '';
533	  const base = metricLabel(f.metric);
534	  const label = platform ? `${platform} · ${base}` : base;
535	  if (typeof f.required === 'boolean') {
536	    return `${label} — need ${f.required ? 'yes' : 'no'}`;
537	  }
538	  const needed = formatCount(f.required);
539	  if (typeof f.actual === 'number') {
540	    return `${label} — have ${formatCount(f.actual)} of ${needed} needed`;
541	  }
542	  return `${label} — need ${needed} (no data yet)`;
543	}
544	
545	function postConditionLabel(c: ConditionRow): string {
546	  switch (c.metric) {
547	    case 'post_family_friendly':
548	      return c.bool_threshold ? 'Family-friendly content only.' : 'Content may be mature.';
549	    case 'post_must_mention':
550	      return c.text_threshold
551	        ? `Must mention ${c.text_threshold}.`
552	        : 'Must include a specific mention.';
553	    case 'post_must_tag_account':
554	      return c.text_threshold
555	        ? `Must tag @${c.text_threshold.replace(/^@/, '')}.`
556	        : 'Must tag the lister account.';
557	    case 'post_min_video_duration_sec':
558	      return c.numeric_threshold !== null
559	        ? `Video at least ${c.numeric_threshold}s.`
560	        : 'Minimum video duration.';
561	    case 'post_max_video_duration_sec':
562	      return c.numeric_threshold !== null
563	        ? `Video at most ${c.numeric_threshold}s.`
564	        : 'Maximum video duration.';
565	    case 'post_min_video_count':
566	      return c.numeric_threshold !== null
567	        ? `Post at least ${c.numeric_threshold} videos.`
568	        : 'Minimum video count.';
569	    default:
570	      return c.metric;
571	  }
572	}
573	
574	function platformLabel(p: Platform): string {
575	  return p === 'tiktok' ? 'TikTok' : 'Instagram';
576	}
577	
578	function formatPrice(priceCents: number, currency: string): string {
579	  const amount = (priceCents / 100).toLocaleString('en-US', {
580	    minimumFractionDigits: 0,
581	    maximumFractionDigits: 2,
582	  });
583	  const code = currency.toUpperCase();
584	  if (code === 'USD') return `$${amount}`;
585	  return `${amount} ${code}`;
586	}
587	
588	function formatCount(n: number): string {
589	  if (n < 1000) return String(n);
590	  const trim = (value: number, digits: number): string => {
591	    const fixed = value.toFixed(digits);
592	    return fixed.endsWith('.0') ? fixed.slice(0, -2) : fixed;
593	  };
594	  if (n < 1_000_000) return `${trim(n / 1000, n < 10_000 ? 1 : 0)}k`;
595	  if (n < 1_000_000_000) return `${trim(n / 1_000_000, n < 10_000_000 ? 1 : 0)}m`;
596	  return `${trim(n / 1_000_000_000, n < 10_000_000_000 ? 1 : 0)}b`;
597	}
